  `created_by_id` bigint DEFAULT NULL,
  `updated_by_id` bigint DEFAULT NULL,
  `category_id` bigint DEFAULT NULL,
  `system-field-id` bigint DEFAULT NULL,
  `module_id` bigint DEFAULT NULL,
  `disabled` bit(1) DEFAULT NULL,
  `field_behavior` varchar(255) DEFAULT NULL,
  `field_order` int DEFAULT NULL,
  `show_grid_column` bit(1) DEFAULT NULL,
  `show_in_view` bit(1) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `UKhlq90hlc2henmua6g7ytpo6vs` (`system-field-id`),
  KEY `FKdddi2sgm0pv91e90cp5wtf6yc` (`created_by_id`),
  KEY `FKr8cv3cvwmu53bndg3p2uh38oy` (`updated_by_id`),
  KEY `FK2rvlybnjea64hpvui0392idlh` (`category_id`),
  KEY `FK3277ajyno2koha29ycbygvhgt` (`module_id`),
  CONSTRAINT `FK2rvlybnjea64hpvui0392idlh` FOREIGN KEY (`category_id`) REFERENCES `category` (`id`),
  CONSTRAINT `FK3277ajyno2koha29ycbygvhgt` FOREIGN KEY (`module_id`) REFERENCES `modules` (`id`),
  CONSTRAINT `FKdddi2sgm0pv91e90cp5wtf6yc` FOREIGN KEY (`created_by_id`) REFERENCES `user` (`id`),
  CONSTRAINT `FKetn47tjyqy7hocw7rmnuv13n7` FOREIGN KEY (`system-field-id`) REFERENCES `system_fields` (`id`),
  CONSTRAINT `FKr8cv3cvwmu53bndg3p2uh38oy` FOREIGN KEY (`updated_by_id`) REFERENCES `user` (`id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
